SELECT MAX(version) AS max_version
FROM document_configurations
WHERE sub_option = 'citation_package' AND document_type = 'research_paper';

SELECT sub_option
FROM document_configurations
WHERE document_type = 'research_paper' AND is_active = 1;

SELECT document_type, updated_at
FROM document_configurations
WHERE config_id = 0;

SELECT COUNT(*) 
FROM document_configurations 
WHERE mth = 1;

SELECT document_type
FROM document_configurations
WHERE version = (SELECT MAX(version) FROM document_configurations);

SELECT COUNT(*) AS active_research_paper_configs
FROM document_configurations
WHERE is_active = 1 AND document_type = 'research_paper';

SELECT COUNT(*) AS total_active_users
FROM users
WHERE is_active = 1 AND user_id IN (
  SELECT DISTINCT changed_by
  FROM config_history
);
